import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() to read the entire line

        // Limit the size of the buffer to prevent buffer overflow
        int bufferSize = Math.min(name.length(), 10);
        char[] buffer = new char[bufferSize];

        // Copy the user input into the fixed-size array with bounds checking
        for (int i = 0; i < bufferSize; i++) {
            buffer[i] = name.charAt(i);
        }

        // Print out the contents of the buffer array
        System.out.println("Buffer contents: ");
        for (char c : buffer) {
            System.out.print(c);
        }

        scanner.close();
    }
}

